<?php namespace App\Enums; enum MaintenanceStatus:string{case Scheduled='scheduled';case DueSoon='due_soon';case Overdue='overdue';case Completed='completed'; public function label():string{return str($this->value)->replace('_',' ')->headline();} public function color():string{return match($this){self::Scheduled=>'blue',self::DueSoon=>'amber',self::Overdue=>'rose',self::Completed=>'emerald'};}}
